const CalendarPicker = ({  data, onConfirm,  initValue, init, last, isRange, appoitmentType }) => {


  const handleChange =  (v) => {
    onConfirm?.(v);
    data.modalID && CloseModal({id:data.modalID})
	}


  const observeComponent = ObserveEvent("fb_updated_1128h");

  // console.log("observeComponent", observeComponent)
 
  return (
      <DatePicker  
        onConfirm={handleChange}
        onCancel={()=>{
          data.modalID && CloseModal({id:data.modalID})
        }}
        initValue={initValue}
        init={init}
        last={last}
        isRange={isRange}
      />
  )
}






const DatePicker = ({ onConfirm, onCancel, init, last, isRange}) => {
  const [initDate, set_initDate] = useState(init);
  const [lastDate, set_lastDate] = useState(last);
  const [isLastDate, set_isLastDate] = useState(false);
  
  
	
  const updDate = (dd) =>{
    if(isRange){
      if(isLastDate && dd>initDate){
        set_lastDate(dd);
        set_isLastDate(false)
      }else{
        set_initDate(dd);
        set_lastDate(null);
        set_isLastDate(true)
      }
    }else{
      set_initDate(dd);
      set_lastDate(null);
      set_isLastDate(true)
    }
  }

  const handleCancel = () =>{
    onCancel()
    
  }

  const handleOk = () =>{
    
      (isRange && initDate && lastDate ||  initDate ) && 
      onConfirm(
        {initDate,lastDate}
      );
    
    
  }

  return (
    <div className="dateBox darkmode" >
     
          <div className="date_header_box"  >
            <div  className={ "date_header_title"}>
                {isRange?"Select Ranges":"Escojer Dia"}
            </div>
          </div>
          <div className={"_dsplFlx date_calendar_header"} >
            <div  className={"date_range_title"}>
                {initDate? parseDateShort(initDate) :"Start Date"}
            </div>
            {isRange?
            <div  className={"date_range_space_title"}>
                {" - "}
            </div>:null}
             {isRange?
            <div  className={"date_range_title"}>
              {lastDate?parseDateShort(lastDate) :"End Date"}
            </div>
            :null}
            <div className="flexSpace"/>
            {/*
            <Icon2 name={"lead-pencil"} color={"var(--light-200)"}/>
            */}
          </div>
         
        <CalendarComponent 
          onChangeDate={updDate}
          init={initDate}
          last={lastDate}
          isRange={isRange}
        />
        
        <div className={"_dsplFlx calendar_action_group"} >
          <div className="flexSpace"/>
          <div
            onClick={handleCancel}
            size={40}
            className={"_dsplFlx"}
          >
            
              <div  className={ "btn_cal_cancel"}>
                {"Cancel"}
              </div>
          </div>
          <div
              onClick={handleOk}
          >
            <div
              className={"_dsplFlx"}
              style={{
                marginLeft: 16,
                marginRight: 8
              }}
            >
              <div  className={ "btn_cal_confirm"}>
              
                {"OK"}
              </div>
            </div>
          </div>
        </div>
    </div>
  )
  

}



export default CalendarPicker;






const CalendarComponent = ({ init, last ,onChangeDate, isRange, appoitmentType}) => {
  const [year, setYear] = useState((new Date()).getFullYear());
	const [month, setMonth] = useState((new Date()).getMonth());
	const [calendarData, setCalendarData] = useState([]);
  const [yearPicker, setYearPicker] = useState(false);
	const [obs, set_obs] = useState(1);
  

  useEffect(() => {
    setCalendarData(renderCalendar(month, year));
    setTimeout(() => {
      set_obs(gen16CodeId())
    }, 350);
    return () => {
      //
    }
  }, [month, year])

  let monthlabel = _monthNames["es"][month+1];





  const changeMonth = (m) =>{
    if(month+m > 11 || month+m < 0){
      let mm = month+m > 11 ? 0 :  month+m < 0 ? 11 : month+m;
      let yy = month+m > 11 ? year+1 : month+m < 0 ? year-1 : year;
      let mdid = yy+"_"+mm;
      //changeMonthAppoitments(mdid)
      setMonth(mm);
      setYear(yy);
    }
    else{
      
      //changeMonthAppoitments(mdid)
      setMonth(month+m);
    }
  }

  const changeYear = (yy) =>{
    setYear(yy);
    setYearPicker(false);
  }

  let hidePrevMtnBtn  = appoitmentType &&  year === (new Date()).getFullYear() && (month <= (new Date()).getMonth());

  const prevMonth = (m) =>{
    if(!hidePrevMtnBtn){
      changeMonth(-1);
      
    }
  }


  const onChange = (day) =>{
    const date = day && (new Date(year,month,day)).getTime();
    //date && onChangeDate(date+60000);
    date && onChangeDate(date);
  }

  


  return (
    <div style={{marginLeft: 4}}>
        <div  className={"_dsplFlx date_calendar_header"} >
            <div
              onClick={()=>setYearPicker(!yearPicker)}
              size={40}
            >
              <div
               className={"_dsplFlx"}
                style={{padding: 8}}
              >
                <div  className={ "date_calendar_header_yearmonth"}>
                  {monthlabel}
                </div>
                <div  className={ "date_calendar_header_yearmonth"}>
                  {year}
                </div>
                <div style={{paddingHorizontal:2}}>
                  <Icon2 name={'arrow_drop_down'} size={24} color={"var(--light-300)"} />
                </div>
              </div>
            </div>
          <div className="flexSpace"/>
          {!yearPicker && (
            <div  className={`_dsplFlx ${hidePrevMtnBtn?"disabled":""}`} >
              <div  style={{borderRadius:50}}>
                <div style={{padding:"0 2px", marginRight: 12}}  onClick={prevMonth}>
                  <Icon2 name={'arrow_left'} size={24} color={"var(--light-200)"} />
                </div>
              </div>
            </div>
            )
          }
           
          {!yearPicker?
           <div
            className={"_dsplFlx"}
            >
              <div  style={{borderRadius:50}}>
                <div style={{padding:"0 2px"}}  onClick={()=>changeMonth(1)}>
                  <Icon2 name={'arrow_right'} size={24} color={"var(--light-200)"} />
                </div>
              </div>
            </div>
          :null}
                    
          </div>
        {!yearPicker?
        <MonthRenderComponent 
          year={year}  
          month={month} 
          calendarData={calendarData} 
          onChange={onChange}
          init={init}
          last={last}
          range={isRange}
          appoitmentType={appoitmentType}
        />
        :
        <YearlistComponent year={year} onChange={changeYear}/> 
      }
    </div>
  )

}





const MonthRenderComponent = ({ year, month,  calendarData, onChange, init, last, range, appoitmentType}) => {

  let dayFactor = 86400000;

  let initSum =  Math.floor(init / dayFactor);
  let lastSum =  Math.floor(last / dayFactor);


  
  let todayTime = new Date((new Date()).getFullYear(),(new Date()).getMonth(),(new Date()).getDate());

 
  return (
      <>
      <div  className={"_dsplFlx date_calendar_week_title"} >
      {_dayShortNames["en"].map((day, wwInd)=>{
        return (
          <div key={day + "_" +wwInd} className={"date_calendar_week_title_day"}>
            {day}
          </div>
        )
      })}
      </div>



      <div style={{minHeight: 282}}>
        {calendarData.map((week, wInd)=>{
          return(
            <div key={"week_"+ wInd} 
            className={"_dsplFlx"}>
                {week.map((dd, dIndx)=>{
                  let day = dd.day;

                  let dayTime = new Date(year,month,day);

                  let hiddePrev = appoitmentType &&  todayTime>dayTime;

                  
                  let daySum =  Math.floor(dayTime / dayFactor);

                  let isSelected = day && daySum > initSum && 
                  daySum < lastSum;

                  let firstValidDate = day && daySum === initSum;
                  let lastValidDate = day && daySum === lastSum;

                  let isToday = dd.isToday;




                  const handleChangeDay = (day) =>{
                    if(!hiddePrev){
                      updStore("isTodayPickApp",isToday);
                      onChange(day);
                    }
                  }


                 
                  
                  return (
                    <div
                      key={dIndx + "_day_" + wInd}
                      className={`day_wrp ${!day?" empty_day":""} ${hiddePrev?" disable_day":""}${range?" range":""}${isToday?" isToday":""}${day && lastValidDate?" lastActiveDay":""}${day && firstValidDate?" firstActiveDay":""}${isSelected?" isSelected":""}`}
                    >
                    <div
                      className={`day_cal `}
                      onClick={()=>handleChangeDay(day)}
                    >
                      <div  
                       className={`day_num `}
                      >
                        {day}
                      </div>
                     
                    </div>
                    </div>
                  )
                })}
            </div>
        )})}
      </div>
    </>
  )

}










const YearlistComponent = ({ year, onChange}) => {
  let yearList = Array.from({length: 108}, (_, i) => i + ((new Date()).getFullYear() - 90));

  let scrollRef = useRef();

  
  useEffect(() => {
    setTimeout(() => {
      let diff = (year - (new Date()).getFullYear()) / 3;
      let halfFactor = (16 + diff)* 41.6;
      scrollRef.current.scrollTo({ x: halfFactor, y: 0, animated: true })
    }, 20);
    return () => {
      //
    }
  }, [year])

  
  return (
        <div>
          <div

            ref={scrollRef}
            //contentInsetAdjustmentBehavior="automatic"
            style={{ maxHeight: "70vh"}}
            className={"scrollV"}
            >
            <div  
              className={"_dsplFlx year_wrp"}
            >
            {yearList.map(yy=>{
              return (
                <div
                  //onLayout={onLayout}
                  key={yy}
                  className={"year_tag"} 
                  onClick={()=>onChange(yy)}
                >
                  <div
                    className={`year-itm${yy===year?" activeYear":""} `}
                  >
                    <div  
                      className={`y_num`}
                    >
                      {yy}
                    </div>
                  </div>
                </div>
              )
            })}
            </div>
          </div>
        </div>
  )
}




















